const data = $input.first().json;
const rows = (data.rows || []).map(r => {
  const sevColor = r.status === 'blocked' ? '#e74c3c' : (r.days_open > 14 ? '#e67e22' : '#3498db');
  const failItems = (r.fail_items || []).map(f => `<li>${f.label}${f.comment ? ' — <i>' + f.comment + '</i>' : ''}</li>`).join('');
  const failBlock = r.failed > 0 ? `<ul style=\"margin:4px 0 0 18px;font-size:11px;color:#7f8c8d\">${failItems}</ul>` : '';
  return '<tr>' +
    '<td><b>' + (r.project_name || '?') + '</b><br><small style=\"color:#7f8c8d\">' + r.phase_key + '</small></td>' +
    '<td><span style=\"background:' + sevColor + ';color:white;padding:3px 8px;border-radius:12px;font-size:11px\">' + r.status + '</span></td>' +
    '<td>' + r.passed + ' pass / ' + r.failed + ' fail / ' + r.pending + ' pending' + failBlock + '</td>' +
    '<td>' + r.days_open + 'd abierto<br><small>' + r.days_no_progress + 'd sin avance</small></td>' +
    '</tr>';
}).join('');
const html = '<h2>QC checklists pendientes de revisión</h2>' +
  '<p>Total stuck: <b>' + data.stuck_count + '</b>. Criterios: <code>blocked &gt; 3 días</code> o <code>open/in_progress &gt; 7 días</code>.</p>' +
  '<table border=\"1\" cellpadding=\"6\" cellspacing=\"0\" style=\"border-collapse:collapse;font-family:sans-serif;font-size:13px\">' +
  '<thead><tr style=\"background:#f3f4f6\"><th>Proyecto / Fase</th><th>Estado</th><th>Items</th><th>Tiempo</th></tr></thead>' +
  '<tbody>' + rows + '</tbody></table>' +
  '<p style=\"font-size:11px;color:#6b7280\">Para cerrar un item: <code>POST /webhook/qc-complete</code> con <code>{qc_id, item_id, status}</code>.</p>';
return [{ json: { html_body: html, count: data.stuck_count } }];

